exercises.solution:
function countPairs(nums, target) {
  const freq = new Map();
  let count = 0;
  for (const n of nums) {
    const need = target - n;
    if (freq.has(need)) count += freq.get(need);
    freq.set(n, (freq.get(n) || 0) + 1);
  }
  return count;
}

exercises.starter:
function runningMedian(stream) {
  // return array of medians after each element
  // sort-on-insert is O(n) per element = O(n²) total — implement it,
  // then note in a comment how a two-heap approach gives O(n log n)
}

exercises.solution:
function runningMedian(stream) {
  const sorted = [];
  return stream.map(n => {
    let lo = 0, hi = sorted.length;
    while (lo < hi) { const mid = (lo+hi)>>1; if (sorted[mid] < n) lo=mid+1; else hi=mid; }
    sorted.splice(lo, 0, n);
    const m = sorted.length;
    return m % 2 === 1 ? sorted[m>>1] : (sorted[m/2-1]+sorted[m/2])/2;
  });
}

