check('sorted order', () => { const h3 = new MinHeap(); [5,3,8,1,4].forEach(v=>h3.push(v)); const out=[]; for(let i=0;i<5;i++) out.push(h3.pop()); expect(out).toEqual([1,3,4,5,8]); });
