exercises.solution:
function bfs(graph, start) {
  const visited = new Set([start]);
  const queue = [start];
  const result = [];
  let head = 0;
  while (head < queue.length) {
    const node = queue[head++];
    result.push(node);
    for (const nb of (graph[node] || [])) {
      if (!visited.has(nb)) { visited.add(nb); queue.push(nb); }
    }
  }
  return result;
}

exercises.starter:
function numIslands(grid) {
  // for each unvisited '1', run DFS and count
  // DFS should mark cells as visited (e.g., set to '0')
}

exercises.solution:
function numIslands(grid) {
  if (!grid.length) return 0;
  const rows = grid.length, cols = grid[0].length;
  let count = 0;
  function dfs(r, c) {
    if (r<0||r>=rows||c<0||c>=cols||grid[r][c]!=='1') return;
    grid[r][c] = '0';
    dfs(r+1,c); dfs(r-1,c); dfs(r,c+1); dfs(r,c-1);
  }
  for (let r=0;r<rows;r++) for (let c=0;c<cols;c++) {
    if (grid[r][c]==='1') { dfs(r,c); count++; }
  }
  return count;
}

exercises.starter:
function maxSlidingWindow(nums, k) {
  // deque stores indices; front is index of max in current window
  // remove indices out of window; remove smaller elements from back
}

exercises.solution:
function maxSlidingWindow(nums, k) {
  const deq = [], res = [];
  for (let i = 0; i < nums.length; i++) {
    while (deq.length && deq[0] < i-k+1) deq.shift();
    while (deq.length && nums[deq[deq.length-1]] < nums[i]) deq.pop();
    deq.push(i);
    if (i >= k-1) res.push(nums[deq[0]]);
  }
  return res;
}

