  // base: dp[0] = 0
  // fill dp[1..amount] using all coins
}

exercises.tests:
check('basic', () => expect(coinChange([1,5,10,25],30)).toBe(2));
check('greedy fails', () => expect(coinChange([1,3,4],6)).toBe(2));
check('impossible', () => expect(coinChange([2],3)).toBe(-1));
