exercises.solution:
function quickselect(nums, k) {
  function partition(arr, lo, hi) {
    const pivot = arr[hi];
    let i = lo;
    for (let j = lo; j < hi; j++) {
      if (arr[j] <= pivot) { [arr[i],arr[j]]=[arr[j],arr[i]]; i++; }
    }
    [arr[i],arr[hi]]=[arr[hi],arr[i]];
    return i;
  }
  function select(arr, lo, hi, target) {
    if (lo === hi) return arr[lo];
    const p = partition(arr, lo, hi);
    if (p === target) return arr[p];
    if (p < target) return select(arr, p+1, hi, target);
    return select(arr, lo, p-1, target);
  }
  return select([...nums], 0, nums.length-1, k-1);
}

exercises.starter:
function countingSort(nums) {
  // O(n + k) time and space where k = max value
  // 1. find max value
  // 2. build frequency array of size max+1
  // 3. reconstruct sorted output
}

exercises.tests:
check('basic', () => expect(countingSort([4,2,2,8,3,3,1])).toEqual([1,2,2,3,3,4,8]));
check('empty', () => expect(countingSort([])).toEqual([]));
check('single', () => expect(countingSort([5])).toEqual([5]));
check('all same', () => expect(countingSort([3,3,3])).toEqual([3,3,3]));
check('sorted already', () => expect(countingSort([1,2,3,4])).toEqual([1,2,3,4]));

exercises.solution:
function countingSort(nums) {
  // O(n + k) time and space, k = max value
  if (!nums.length) return [];
  const max = Math.max(...nums);
  const freq = new Array(max+1).fill(0);
  for (const n of nums) freq[n]++;
  const out = [];
  for (let v = 0; v <= max; v++) {
    for (let i = 0; i < freq[v]; i++) out.push(v);
  }
  return out;
}
